#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=3e2+5;
int n,m,q,f[MAXN],t[MAXN],ans;
void find(int i){++t[i];if(f[i])find(f[i]);}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d",&n);
	for(int i=1;i<n;++i)scanf("%d",f+i);
	scanf("%d",&q);
	for(int i=0;i<q;++i){
		memset(t,0,sizeof t);scanf("%d",&m);ans=0;
		for(int i=1,x;i<=m;++i){scanf("%d",&x);find(x);}
		for(int i=n-1;i>0;--i){if(t[i]==m){ans=i;break;}}
		printf("%d\n",ans);
	}return false;
}
